import{_ as a,o,c as i,a6 as t}from"./chunks/framework.CG5ubMb2.js";const b=JSON.parse('{"title":"index","description":"Creates an anonymous stub function","frontmatter":{"title":"index","description":"Creates an anonymous stub function"},"headers":[],"relativePath":"concepts/stubs/api/index.md","filePath":"concepts/stubs/api/index.md"}'),l={name:"concepts/stubs/api/index.md"};function r(s,e,c,d,n,h){return o(),i("div",null,[...e[0]||(e[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /concepts/stubs/api.md for this page in Markdown format</div><h1 id="stub-api" tabindex="-1">Stub API <a class="header-anchor" href="#stub-api" aria-label="Permalink to “Stub API”">​</a></h1><h2 id="creating-a-stub" tabindex="-1">Creating a stub <a class="header-anchor" href="#creating-a-stub" aria-label="Permalink to “Creating a stub”">​</a></h2><h3 id="sinon-stub" tabindex="-1"><code>sinon.stub()</code> <a class="header-anchor" href="#sinon-stub" aria-label="Permalink to “sinon.stub()”">​</a></h3><p>Creates an anonymous stub function</p><h3 id="sinon-stub-object-method" tabindex="-1"><code>sinon.stub(object, &quot;method&quot;)</code> <a class="header-anchor" href="#sinon-stub-object-method" aria-label="Permalink to “sinon.stub(object, &quot;method&quot;)”">​</a></h3><p>Replaces <code>object.method</code> with a stub function. An exception is thrown if the property is not already a function.</p><p>The original function can be restored by calling <code>object.method.restore()</code> (or <code>stub.restore()</code>).</p><h2 id="advanced-use" tabindex="-1">Advanced use <a class="header-anchor" href="#advanced-use" aria-label="Permalink to “Advanced use”">​</a></h2><h3 id="sinon-stub-obj" tabindex="-1"><code>sinon.stub(obj)</code> <a class="header-anchor" href="#sinon-stub-obj" aria-label="Permalink to “sinon.stub(obj)”">​</a></h3><p>Stubs all the object&#39;s methods.</p><p>Note that it&#39;s usually better practice to stub individual methods, particularly on objects that you don&#39;t understand or control all the methods for (e.g. library dependencies).</p><p>Stubbing individual methods shows intent more precisely and is less susceptible to unexpected behavior as the object&#39;s code evolves.</p><h3 id="sinon-createstubinstance-myconstructor-overrides" tabindex="-1"><code>sinon.createStubInstance(MyConstructor, overrides)</code> <a class="header-anchor" href="#sinon-createstubinstance-myconstructor-overrides" aria-label="Permalink to “sinon.createStubInstance(MyConstructor, overrides)”">​</a></h3><p>When you want to create a stub object of <code>MyConstructor</code>, but don&#39;t want the constructor to be invoked, use this utility function.</p><p><code>overrides</code> is an optional map overriding created stubs, for example:</p><p>is the same as:</p><p>If provided value is not a stub, it will be used as the returned value:</p><p>is the same as:</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><ul><li><a href="./add-behavior"><code>addBehavior</code></a></li><li><a href="./call-arg"><code>callArg</code></a></li><li><a href="./call-arg-with"><code>callArgWith</code></a></li><li><a href="./calls-arg"><code>callsArg</code></a></li><li><a href="./calls-arg-async"><code>callsArgAsync</code></a></li><li><a href="./calls-arg-on"><code>callsArgOn</code></a></li><li><a href="./calls-arg-on-with"><code>callsArgOnWith</code></a></li><li><a href="./calls-arg-on-with-async"><code>callsArgOnWithAsync</code></a></li><li><a href="./calls-arg-with"><code>callsArgWith</code></a></li><li><a href="./calls-arg-with-async"><code>callsArgWithAsync</code></a></li><li><a href="./calls-fake"><code>callsFake</code></a></li><li><a href="./calls-through"><code>callsThrough</code></a></li><li><a href="./call-through-with-new"><code>callThroughWithNew</code></a></li><li><a href="./get"><code>get</code></a></li><li><a href="./on-call"><code>onCall</code></a></li><li><a href="./on-first-call"><code>onFirstCall</code></a></li><li><a href="./on-second-call"><code>onSecondCall</code></a></li><li><a href="./on-third-call"><code>onThirdCall</code></a></li><li><a href="./rejects"><code>rejects</code></a></li><li><a href="./reset"><code>reset</code></a></li><li><a href="./reset-behavior"><code>resetBehavior</code></a></li><li><a href="./reset-history"><code>resetHistory</code></a></li><li><a href="./resolves"><code>resolves</code></a></li><li><a href="./resolves-arg"><code>resolvesArg</code></a></li><li><a href="./returns"><code>returns</code></a></li><li><a href="./returns-this"><code>returnsThis</code></a></li><li><a href="./set"><code>set</code></a></li><li><a href="./throws"><code>throws</code></a></li><li><a href="./throws-arg"><code>throwsArg</code></a></li><li><a href="./value"><code>value</code></a></li><li><a href="./with-args"><code>withArgs</code></a></li><li><a href="./yield"><code>yield</code></a></li><li><a href="./yield-to"><code>yieldTo</code></a></li><li><a href="./yields"><code>yields</code></a></li><li><a href="./yields-async"><code>yieldsAsync</code></a></li><li><a href="./yields-on"><code>yieldsOn</code></a></li><li><a href="./yields-on-async"><code>yieldsOnAsync</code></a></li><li><a href="./yields-right"><code>yieldsRight</code></a></li><li><a href="./yields-to"><code>yieldsTo</code></a></li><li><a href="./yields-to-async"><code>yieldsToAsync</code></a></li><li><a href="./yields-to-on"><code>yieldsToOn</code></a></li><li><a href="./yields-to-on-async"><code>yieldsToOnAsync</code></a></li></ul><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><ul><li><a href="./wrapped-method"><code>wrappedMethod</code></a></li></ul><hr>',24)])])}const f=a(l,[["render",r]]);export{b as __pageData,f as default};
